            ///   { "type":"column",   "children":[UiNode,...], "gap":4  }
            ///   { "type":"group",    "label":"Section",       "children":[UiNode,...] }
            ///   { "type":"scroll",   "child":UiNode,          "height":300            }
            ///   { "type":"spacer",   "height":8               }
            ///   { "type":"separator"                          }
            ///
            /// DISPLAY  (no id, no events)
            ///   { "type":"text",     "value":"hello",   "size":"sm|md|lg", "muted":true }
            ///   { "type":"heading",  "value":"Title",   "level":1          }
            ///   { "type":"badge",    "label":"WARN",    "color":"#f59e0b"  }
            ///   { "type":"code",     "value":"...",     "language":"json"  }
            ///   { "type":"markdown", "value":"**bold**"                    }
