            ///   { "type":"multi-select",   "id":"tags",  "label":"Tags",   "value":["a"],
            ///                              "options":[{"value":"a","label":"Tag A"},...]  }
            ///   { "type":"checkbox",       "id":"ssl",   "label":"Verify SSL", "checked":true  }
