            ///                              "value":30,   "min":1, "max":300            }
            ///   { "type":"key-value-list", "id":"hdrs",  "label":"Headers",
            ///                              "entries":[{"key":"...","value":"..."}],
            ///                              "add-label":"Add header"                    }
            ///
